                </div>
              </div>
            </div>

            {/* 30% Scroll - Feature 1 */}
            <div className="ev-text-1 ev-text-overlay absolute inset-0 flex items-center justify-start md:pl-32 xl:pl-48 opacity-0 pointer-events-none">
