                  <Plus className="w-4 h-4 text-emerald-400" /> New Station
                </h2>
                <button
                  onClick={() => {
                    setShowForm(false)
                    setSelectedLocation(null)
                  }}
                  className="text-white/50 hover:text-white text-sm"
                >
                  Cancel
                </button>
              </div>

              {/* Selected Location */}
              <div className="rounded-xl border border-white/10 bg-black/40 p-3">
